css:
* { margin: 0; padding: 0; box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; }
body { background: #0a0e1a; color: white; }
.layout { display: flex; min-height: 100vh; }
.sidebar { width: 220px; background: #0f1320; border-right: 1px solid rgba(255,255,255,0.06); padding: 28px 18px; flex-shrink: 0; }
.logo { font-size: 18px; font-weight: 800; margin-bottom: 32px; padding-left: 8px; }
nav { display: flex; flex-direction: column; gap: 4px; }
nav a { display: flex; align-items: center; gap: 12px; padding: 11px 12px; border-radius: 10px; color: rgba(255,255,255,0.5); font-size: 14px; font-weight: 600; cursor: pointer; text-decoration: none; }
nav a span { font-size: 16px; }
nav a.active { background: rgba(239,68,68,0.12); color: #f87171; }
.content { flex: 1; padding: 32px 36px; max-width: 1100px; }
header { display: flex; justify-content: space-between; align-items: flex-end; margin-bottom: 26px; flex-wrap: wrap; gap: 12px; }
header h1 { font-size: 26px; font-weight: 800; }
header p { color: rgba(255,255,255,0.4); font-size: 13px; margin-top: 4px; }
.date { background: rgba(255,255,255,0.05); border: 1px solid rgba(255,255,255,0.08); padding: 9px 16px; border-radius: 10px; font-size: 13px; font-weight: 600; color: rgba(255,255,255,0.7); }
.rings { display: grid; grid-template-columns: repeat(auto-fit, minmax(140px, 1fr)); gap: 14px; margin-bottom: 22px; }
.ring-card { background: rgba(255,255,255,0.03); border: 1px solid rgba(255,255,255,0.07); border-radius: 16px; padding: 18px; display: flex; flex-direction: column; align-items: center; gap: 10px; }
.ring { width: 100px; height: 100px; border-radius: 50%; display: flex; flex-direction: column; align-items: center; justify-content: center; background: conic-gradient(var(--c) calc(var(--p) * 1%), rgba(255,255,255,0.07) 0); position: relative; }
.ring::before { content: ""; position: absolute; inset: 8px; border-radius: 50%; background: #0a0e1a; }
.ring-val { position: relative; font-size: 16px; font-weight: 800; }
.ring-label { position: relative; font-size: 11px; color: rgba(255,255,255,0.45); }
.ring-goal { font-size: 11.5px; color: rgba(255,255,255,0.4); }
.grid { display: grid; grid-template-columns: 1fr 1.2fr; gap: 16px; margin-bottom: 16px; }
.panel { background: rgba(255,255,255,0.03); border: 1px solid rgba(255,255,255,0.07); border-radius: 18px; padding: 22px; }
.panel-head { display: flex; justify-content: space-between; align-items: center; margin-bottom: 18px; }
.panel-head h2 { font-size: 15px; font-weight: 700; }
.badge { background: rgba(239,68,68,0.12); color: #f87171; font-size: 11px; font-weight: 700; padding: 4px 10px; border-radius: 999px; }
.heart-rate { display: flex; align-items: baseline; gap: 8px; margin-bottom: 14px; }
.bpm { font-size: 40px; font-weight: 800; color: #ef4444; }
.bpm-unit { font-size: 13px; color: rgba(255,255,255,0.4); font-weight: 600; }
.pulse-line { margin-top: 10px; height: 50px; }
.pulse-line svg { width: 100%; height: 100%; }
.hr-range { display: flex; gap: 18px; }
.hr-item { display: flex; align-items: center; gap: 8px; font-size: 12.5px; color: rgba(255,255,255,0.55); }
.dot { width: 8px; height: 8px; border-radius: 50%; display: inline-block; }
.bars { display: flex; align-items: flex-end; gap: 10px; height: 130px; }
.bar { flex: 1; background: rgba(255,255,255,0.08); border-radius: 8px 8px 0 0; cursor: pointer; }
.bar.active { background: linear-gradient(180deg, #f87171, #ef4444); }
.bar-labels { display: flex; gap: 10px; margin-top: 10px; }
.bar-labels span { flex: 1; text-align: center; font-size: 11px; color: rgba(255,255,255,0.35); }
.meals { display: flex; flex-direction: column; gap: 12px; }
.meal { display: flex; align-items: center; gap: 14px; }
.meal-icon { font-size: 24px; }
.minfo { display: flex; flex-direction: column; gap: 2px; flex: 1; }
.minfo span:first-child { font-size: 14px; font-weight: 600; }
.msub { font-size: 12px; color: rgba(255,255,255,0.4); }
.mkcal { font-size: 13px; font-weight: 700; color: #f87171; }
@media (max-width: 800px) { .layout { flex-direction: column; } .sidebar { width: 100%; display: flex; } nav { flex-direction: row; overflow-x: auto; } .grid { grid-template-columns: 1fr; } }
